import { GoogleGenAI, Type } from "@google/genai";
import { SchemeMetadata, Lesson } from "../types";

export interface ExtractedSyllabusInfo {
  subject: string;
  form: string;
  recommendedWeeksPerTerm: number;
}

export const extractSyllabusInfo = async (
  syllabusFile: { data: string, mimeType: string }
): Promise<ExtractedSyllabusInfo> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: {
      parts: [
        { text: "Analyze this syllabus. Identify the subject, target form/grade, and recommended weeks per term (usually 10-13) for a 3-term academic year." },
        { inlineData: syllabusFile }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          subject: { type: Type.STRING },
          form: { type: Type.STRING },
          recommendedWeeksPerTerm: { type: Type.INTEGER },
        },
        required: ["subject", "form", "recommendedWeeksPerTerm"],
      }
    }
  });

  try {
    const text = response.text ?? "";
    return JSON.parse(text.trim());
  } catch (error) {
    return { subject: "", form: "", recommendedWeeksPerTerm: 12 };
  }
};

/**
 * Generates a specific chunk of lessons to ensure extreme detail and prevent truncation.
 */
export const generateLessonChunk = async (
  term: number,
  startLesson: number,
  endLesson: number,
  metadata: SchemeMetadata, 
  syllabusFile?: { data: string, mimeType: string }
): Promise<Partial<Lesson>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const textPrompt = `
    Act as a Senior Curriculum Specialist. You are creating a specific batch of lessons for a detailed Scheme of Work.

    TARGET: TERM ${term}, LESSONS ${startLesson} TO ${endLesson}.

    CRITICAL QUALITY MANDATE:
    1. EXTREME DETAIL: Every field must be exhaustive. No generic placeholders.
    2. RESOURCES: List specific textbooks (incl. page ranges), exact laboratory equipment (quantities and types), specific digital links (YouTube, Simulations), and detailed visual aids.
    3. EVALUATION CRITERIA: Must be highly specific success indicators. What EXACTLY must the pupil do to show mastery? Use measurable verbs.
    4. OBJECTIVES: "Pupils will be able to..." followed by at least 3 high-level Bloom's taxonomy objectives.
    5. ACTIVITIES: Step-by-step classroom procedure including introduction, core activity, and plenary.

    Metadata:
    - Subject: ${metadata.subject}
    - Level: Form ${metadata.form}
    - Term: ${term}

    CONTEXT: This is for a 3-term year where each term has 72 lessons. Ensure the content for lessons ${startLesson}-${endLesson} is appropriate for this stage of the syllabus.

    Output format:
    Return an array of objects for lessons ${startLesson} through ${endLesson}.
    Each object: { "term": ${term}, "week": number, "lessonNumber": number, "topic": string, "objectives": string, "activities": string, "resources": string, "assessment": string, "homework": string, "evaluation": string }
  `;

  const contents = syllabusFile 
    ? { parts: [{ text: textPrompt }, { inlineData: syllabusFile }] }
    : textPrompt;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: contents,
    config: {
      thinkingConfig: { thinkingBudget: 2000 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            term: { type: Type.INTEGER },
            week: { type: Type.INTEGER },
            lessonNumber: { type: Type.INTEGER },
            topic: { type: Type.STRING },
            objectives: { type: Type.STRING },
            activities: { type: Type.STRING },
            resources: { type: Type.STRING },
            assessment: { type: Type.STRING },
            homework: { type: Type.STRING },
            evaluation: { type: Type.STRING },
          },
          required: ["term", "week", "lessonNumber", "topic", "objectives", "activities", "resources", "assessment", "homework", "evaluation"],
        }
      }
    }
  });

  try {
    const text = response.text ?? "";
    const result = JSON.parse(text.trim());
    if (!Array.isArray(result)) throw new Error("Output is not an array");
    return result;
  } catch (error) {
    console.error(`Batch ${startLesson}-${endLesson} failed:`, error);
    throw new Error(`Failed to generate lessons ${startLesson}-${endLesson}. API limit or timeout.`);
  }
};

export const generateLessonResourcesContent = async (
  lesson: Lesson,
  metadata: SchemeMetadata
): Promise<Pick<Lesson, 'lessonPlanContent' | 'worksheetContent' | 'slidesContent' | 'videoGuideDescription'>> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `Generate a hyper-detailed teaching package for Topic: "${lesson.topic}". 
    Reference existing resources: "${lesson.resources}".
    Evaluation criteria to hit: "${lesson.evaluation}".

    Package must include:
    1. A 600-word Lesson Plan.
    2. A 15-question comprehensive Worksheet.
    3. 7 Content-rich Presentation Slides.
    4. A Video Script.

    Use "Pupils" throughout.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          lessonPlanContent: { type: Type.STRING },
          worksheetContent: { type: Type.STRING },
          slidesContent: { type: Type.ARRAY, items: { type: Type.STRING } },
          videoGuideDescription: { type: Type.STRING },
        },
        required: ["lessonPlanContent", "worksheetContent", "slidesContent", "videoGuideDescription"],
      }
    }
  });
  const text = response.text ?? "";
  return JSON.parse(text.trim());
};

import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import * as XLSX from "xlsx";
import * as docx from "docx";
import JSZip from "jszip";
import { SchemeBook, Lesson, SchemeMetadata } from "../types";

const { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, Table, TableRow, TableCell, WidthType, BorderStyle, PageOrientation } = docx;

const sanitizeText = (text: any): string => {
  if (text === null || text === undefined) return "";
  return String(text).replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F-\x84\x86-\x9F\uFDD0-\uFDEF\uFFFE\uFFFF]/g, "");
};

const createCellContent = (text: string, size: number, isBold: boolean = false) => {
  const sanitized = sanitizeText(text);
  const runs = sanitized.split(/\r?\n/).map((line, idx) => new TextRun({ text: line, size, bold: isBold, break: idx > 0 ? 1 : undefined }));
  return [new Paragraph({ children: runs })];
};

export const exportToPDF = (scheme: SchemeBook) => {
  const doc = new jsPDF({ orientation: "landscape", unit: 'mm', format: 'a4' });

  [1, 2, 3].forEach((termNum, index) => {
    const termLessons = scheme.lessons.filter(l => l.term === termNum);
    if (termLessons.length === 0) return;

    if (index > 0) doc.addPage();

    doc.setFontSize(14);
    doc.text(`${scheme.metadata.subject} - TERM ${termNum}`, 14, 15);
    doc.setFontSize(8);
    doc.text(`${scheme.metadata.school} | Form: ${scheme.metadata.form} | Year: ${scheme.metadata.academicYear}`, 14, 20);

    const body = termLessons.map(l => [
      l.week, 
      l.lessonNumber,
      l.weekEnding, 
      l.topic, 
      l.objectives, 
      l.activities, 
      l.resources,
      l.assessment,
      l.evaluation,
      "" // Remarks column
    ]);

    autoTable(doc, {
      startY: 25,
      head: [['Wk', 'L#', 'Date', 'Topic', 'Learning Objectives', 'Activities', 'Resources', 'Asmt', 'Eval Criteria', 'Remarks']],
      body: body,
      theme: 'grid',
      styles: { 
        fontSize: 6, 
        cellPadding: 0.8,
        valign: 'top',
        overflow: 'linebreak'
      },
      headStyles: { 
        fillColor: [51, 65, 85],
        textColor: 255,
        fontSize: 6.5,
        fontStyle: 'bold'
      },
      columnStyles: {
        0: { cellWidth: 7 },  // Wk
        1: { cellWidth: 7 },  // L#
        2: { cellWidth: 18 }, // Date
        3: { cellWidth: 32 }, // Topic
        4: { cellWidth: 42 }, // Objectives
        5: { cellWidth: 42 }, // Activities
        6: { cellWidth: 28 }, // Resources
        7: { cellWidth: 20 }, // Assmt
        8: { cellWidth: 32 }, // Eval Criteria
        9: { cellWidth: 22 }  // Remarks
      },
      margin: { top: 25, right: 8, bottom: 8, left: 8 }
    });
  });

  doc.save(`${scheme.metadata.subject}_Scheme_${scheme.metadata.academicYear.replace('/', '-')}.pdf`);
};

export const exportToWord = async (scheme: SchemeBook) => {
  const children: any[] = [
    new Paragraph({ 
      text: `${scheme.metadata.subject} Full Year Scheme`, 
      heading: HeadingLevel.HEADING_1, 
      alignment: AlignmentType.CENTER 
    }),
    new Paragraph({ 
      text: `${scheme.metadata.school} - Form ${scheme.metadata.form} - Academic Year ${scheme.metadata.academicYear}`, 
      alignment: AlignmentType.CENTER,
      spacing: { after: 400 }
    })
  ];

  [1, 2, 3].forEach(termNum => {
    const termLessons = scheme.lessons.filter(l => l.term === termNum);
    if (termLessons.length === 0) return;

    children.push(new Paragraph({ text: `TERM ${termNum}`, heading: HeadingLevel.HEADING_2, spacing: { before: 400, after: 200 } }));

    const headerRow = new TableRow({ 
      children: ['Wk', 'L#', 'Date', 'Topic', 'Learning Objectives', 'Activities', 'Res', 'Asmt', 'Eval', 'Rem'].map(h => 
        new TableCell({ 
          shading: { fill: "334155" },
          children: [new Paragraph({ 
            alignment: AlignmentType.CENTER,
            children: [new TextRun({ text: h, color: "FFFFFF", size: 16, bold: true })] 
          })] 
        })
      ) 
    });

    const rows = termLessons.map(l => new TableRow({
      children: [
        new TableCell({ width: { size: 4, type: WidthType.PERCENTAGE }, children: createCellContent(l.week.toString(), 14) }),
        new TableCell({ width: { size: 4, type: WidthType.PERCENTAGE }, children: createCellContent(l.lessonNumber.toString(), 14) }),
        new TableCell({ width: { size: 8, type: WidthType.PERCENTAGE }, children: createCellContent(l.weekEnding, 14) }),
        new TableCell({ width: { size: 12, type: WidthType.PERCENTAGE }, children: createCellContent(l.topic, 14, true) }),
        new TableCell({ width: { size: 16, type: WidthType.PERCENTAGE }, children: createCellContent(l.objectives, 14) }),
        new TableCell({ width: { size: 16, type: WidthType.PERCENTAGE }, children: createCellContent(l.activities, 14) }),
        new TableCell({ width: { size: 12, type: WidthType.PERCENTAGE }, children: createCellContent(l.resources, 14) }),
        new TableCell({ width: { size: 8, type: WidthType.PERCENTAGE }, children: createCellContent(l.assessment, 14) }),
        new TableCell({ width: { size: 12, type: WidthType.PERCENTAGE }, children: createCellContent(l.evaluation, 14) }),
        new TableCell({ width: { size: 8, type: WidthType.PERCENTAGE }, children: createCellContent("", 14) })
      ]
    }));

    children.push(new Table({
      width: { size: 100, type: WidthType.PERCENTAGE },
      rows: [headerRow, ...rows],
      borders: {
        top: { style: BorderStyle.SINGLE, size: 1 },
        bottom: { style: BorderStyle.SINGLE, size: 1 },
        left: { style: BorderStyle.SINGLE, size: 1 },
        right: { style: BorderStyle.SINGLE, size: 1 },
      }
    }));
  });

  const doc = new Document({ 
    sections: [{ 
      properties: { 
        page: { 
          size: {
            orientation: PageOrientation.LANDSCAPE,
          },
          margin: { top: 400, right: 400, bottom: 400, left: 400 }
        } 
      }, 
      children 
    }] 
  });

  const blob = await Packer.toBlob(doc);
  const link = document.createElement("a");
  link.href = URL.createObjectURL(blob);
  link.download = `${scheme.metadata.subject}_Scheme_${scheme.metadata.academicYear.replace('/', '-')}.docx`;
  link.click();
};

export const exportToExcel = (scheme: SchemeBook) => {
  const data = scheme.lessons.map(l => ({
    "Term": l.term,
    "Week": l.week,
    "Lesson #": l.lessonNumber,
