const InputForm: React.FC<InputFormProps> = ({ onGenerate }) => {
  const [inputMode, setInputMode] = useState<'upload' | 'manual'>('upload');
  const [formData, setFormData] = useState<SchemeMetadata>({
    subject: '',
    form: '',
    weeksPerTerm: 12,
    lessonsPerWeek: 6,
    lessonsPerTerm: 72,
    teacherName: '',
    school: '',
    academicYear: getAcademicYears()[0],
    manualTopics: '',
